package be.schaubroeck.lpb.rkm.rekenmotor.voorbereiding;

import be.schaubroeck.lpb.rkm.rekenmotor.CoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenMotorStrategy;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenMotorStrategyFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenAtoom;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenenHelpService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenmotorDtoConverter;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenmotorService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.web.RekenProcesImp;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MetaRekenFeedback;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenFeedback;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ElektronischeVoorbereiding;
import be.schaubroeck.lpb.tools.Werkgever;
import be.schaubroeck.lpb.tools.enumtypes.RekenLogStatus;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import be.schaubroeck.lpb.tools.exception.ProcesHaltedException;
import be.schaubroeck.lpb.tools.service.KalAfsluitenOpdrachtService;
import be.schaubroeck.lpb.tools.service.KalAfsluitenService;
import be.schaubroeck.lpb.tools.service.OpdrachtService;
import be.schaubroeck.lpb.tools.service.WerkgeverService;
import be.schaubroeck.temporal.util.TemporalContext;
import com.google.common.collect.SetMultimap;
import com.google.common.collect.TreeMultimap;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDateTime;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Lazy;
import org.springframework.stereotype.Service;

import java.util.Collection;
import java.util.List;
import java.util.Set;

@Slf4j
@Lazy
@Service
public class AlgemeneRekenUitVoorbereidingService {

    @Autowired
    private KalAfsluitenOpdrachtService kalAfsluitenOpdrachtService;
    @Autowired
    private KalAfsluitenService kalAfsluitenService;
    @Autowired
    private OpdrachtService opdrachtService;
    @Autowired
    private WerkgeverService werkgeverService;
    @Autowired
    private RekenMotorStrategyFactory rekenMotorStrategyFactory;
    @Autowired
    private RekenmotorService rekenmotorService;
    @Autowired
    private RekenenHelpService rekenenHelpService;
    @Autowired
    private RekenAtomenCollector rekenAtomenCollector;


    public List<RekenVoorbereiding> maakVoorbereidingen(Collection<ElektronischeVoorbereiding> eVoorbereidingen, Admin admin) {
        RekenVoorbereidingFactory factory = new RekenVoorbereidingFactory(kalAfsluitenOpdrachtService, opdrachtService, kalAfsluitenService);
        return factory.create(admin, eVoorbereidingen);
    }

    public RekenmotorDtoConverter getConverter(Admin admin) {
        List<Werkgever> werkgevers = werkgeverService.findByAdmin(admin, "");
        return new RekenmotorDtoConverter(werkgevers);
    }

    public RekenUitVoorbereidingStatus doeBerekeningenUitRekenAgenda(
            Admin admin, Integer rekenBatchNr, SetMultimap<RekenAtoom, Integer> rekenAtomenMap, String actor, MetaRekenFeedback metaFeedback,
            CoreHrConfiguratie coreHrConfiguratie) {
        Rekenmodus modus = Rekenmodus.NORMAAL;
        RekenMotorStrategy strategy = rekenMotorStrategyFactory.getMaandTotalenStrategy(admin);

        strategy.getResultaatHandler().setRekenBatchNr(rekenBatchNr);
        strategy.getArtikelMotorResultaatHandler().setRekenBatchNr(rekenBatchNr);

        RekenUitVoorbereidingStatus rekenUitVoorbereidingStatus = RekenUitVoorbereidingStatus.builder()
                .status(RekenLogStatus.SUCCES)
                .heeftReguls(false)
                .heeftWaarschuwingen(false)
                .build();

        RekenContext rekenContext = new RekenContext();
        for (RekenAtoom atoom : rekenAtomenMap.keySet()) {
            Set<Integer> opdrachtNrs = rekenAtomenMap.get(atoom);
            checkInterupted();
            try {
                rekenContext =
                        rekenmotorService.berekenLoon(admin, atoom.getPersoonId(), opdrachtNrs, atoom.getRekenTijd(), strategy, modus, actor, coreHrConfiguratie);
                RegulManager regulManager = rekenContext.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
                boolean heeftReguls = rekenUitVoorbereidingStatus.heeftReguls || (regulManager != null && regulManager.hasReguls());
                rekenUitVoorbereidingStatus.setHeeftReguls(heeftReguls);
                boolean heeftWaarschuwingen = rekenUitVoorbereidingStatus.heeftWaarschuwingen || (regulManager != null && regulManager.heeftWaarschuwingen());
                rekenUitVoorbereidingStatus.setHeeftWaarschuwingen(heeftWaarschuwingen);
            } catch (Exception exception) {
                rekenUitVoorbereidingStatus.setStatus(RekenLogStatus.FATAL_ERROR);
                rekenenHelpService.logFatalException(admin, atoom.getRekenTijd().beginDatum, atoom.getPersoonId(), opdrachtNrs, exception);
            }
            RekenFeedback rekenFeedback = metaFeedback.rekenFeedbackPerAtoom(atoom, rekenContext.getUnchecked(RekenChainKey.REKEN_FEEDBACK_KEY));
            RekenProcesImp.incrementVerwerktStatic();
            try {
                rekenenHelpService.doeRekenLog(admin, atoom.getPersoonId(), opdrachtNrs, atoom.getRekenTijd(), modus, rekenUitVoorbereidingStatus.status, rekenFeedback,
                        actor);
            } catch (Exception exception) {
                log.debug("Logging failed", exception);
            }
        }
        return rekenUitVoorbereidingStatus;
    }

    public SetMultimap<RekenAtoom, Integer> bepaalRekenAtomen(
            List<RkmCoreHrConfiguratie> rkmCoreHrConfiguraties, Collection<RekenVoorbereiding> voorbereidingen, RekenmotorDtoConverter converter) {
        LocalDateTime rekenTijdstip = TemporalContext.getInstance().getWerkTijdstip();

        SetMultimap<RekenAtoom, Integer> voorbereidingToAtomenMap = TreeMultimap.create();
        for (RekenVoorbereiding punt : voorbereidingen) {
            log.info("bepaalRekenAtomen voorbereiding {}", punt.getElektronischeVoorbereiding().getId());
            voorbereidingToAtomenMap.putAll(rekenAtomenCollector.bepaalRekenAtomen(punt, rekenTijdstip));
            if (rekenAtomenCollector.getGewijzigdeGegevens(converter, rkmCoreHrConfiguraties, punt)) {
                voorbereidingToAtomenMap.putAll(rekenAtomenCollector.bepaalRekenAtomenVoorHoedanigHeidOfRekenGroep(punt, rekenTijdstip));
            }
        }
        log.trace("bepaalRekenAtomen voorbereidingToAtomenMap: {}", voorbereidingToAtomenMap.keySet());
        return voorbereidingToAtomenMap;
    }

    private void checkInterupted() {
        if (RekenProcesImp.isInStopState()) {
            throw new ProcesHaltedException("Shall halt");
        }
    }

}
